import scrapy
class BookSpider(scrapy.Spider):
    name = "BookSpider"
    start_urls = ["http://books.example.com/list"]
    def parse(self, response):
        # 提取书籍信息
        book_items = response.css("div.book-item")
        for item in book_items:
            book_name = item.css("h3.title::text").get(strip=True)
            author = item.css("span.author::text").get(strip=True)
            yield {
                "book_name": book_name,
                "author": author
            }
        # 处理翻页
        next_url = response.css("a.next::attr(href)").get()
        if next_url:
            yield scrapy.Request(url=next_url, callback=self.parse)
